     3→import { useRef, useEffect, useCallback, useState } from 'react';
     4→import { SendIcon, StopIcon, PaperclipIcon, XIcon, FileTextIcon, MicIcon } from './icons.js';
     5→import { useVoiceInput } from '../../voice/use-voice-input.js';
     6→import { getVoiceToken } from '../../voice/actions.js';
     7→import { VoiceBars } from './voice-bars.jsx';
     8→import { cn } from '../utils.js';
     9→
    10→const ACCEPTED_TYPES = [
    11→  'image/jpeg', 'image/png', 'image/gif', 'image/webp',
    12→  'application/pdf',
    13→  'text/plain', 'text/markdown', 'text/csv', 'text/html', 'text/css',
    14→  'text/javascript', 'text/x-python', 'text/x-typescript',
    15→  'application/json',
    16→];
    17→
    18→const MAX_FILES = 5;
    19→
    20→function isAcceptedType(file) {
    21→  if (ACCEPTED_TYPES.includes(file.type)) return true;
    22→  // Fall back to extension for files with generic MIME types
    23→  const ext = file.name?.split('.').pop()?.toLowerCase();
    24→  const textExts = ['txt', 'md', 'csv', 'json', 'js', 'ts', 'jsx', 'tsx', 'py', 'html', 'css', 'yml', 'yaml', 'xml', 'sh', 'bash', 'rb', 'go', 'rs', 'java', 'c', 'cpp', 'h', 'hpp'];
    25→  return textExts.includes(ext);
    26→}
    27→
    28→function getEffectiveType(file) {
    29→  if (ACCEPTED_TYPES.includes(file.type) && file.type !== '') return file.type;
    30→  const ext = file.name?.split('.').pop()?.toLowerCase();
    31→  const extMap = {
    32→    txt: 'text/plain', md: 'text/markdown', csv: 'text/csv',
    33→    json: 'application/json', js: 'text/javascript', ts: 'text/x-typescript',
    34→    jsx: 'text/javascript', tsx: 'text/x-typescript', py: 'text/x-python',
    35→    html: 'text/html', css: 'text/css', yml: 'text/plain', yaml: 'text/plain',
    36→    xml: 'text/plain', sh: 'text/plain', bash: 'text/plain', rb: 'text/plain',
    37→    go: 'text/plain', rs: 'text/plain', java: 'text/plain', c: 'text/plain',
    38→    cpp: 'text/plain', h: 'text/plain', hpp: 'text/plain',
    39→  };
    40→  return extMap[ext] || file.type || 'text/plain';
    41→}
    42→
    43→export function ChatInput({ input, setInput, onSubmit, status, stop, files, setFiles, disabled = false, placeholder = 'Send a message...', canSendOverride, bare = false, className, codeMode = false, codeModeSettings }) {
    44→  const textareaRef = useRef(null);
    45→  const fileInputRef = useRef(null);
    46→  const [isDragging, setIsDragging] = useState(false);
    47→  const [modeDropdownOpen, setModeDropdownOpen] = useState(false);
    48→  const dropdownRef = useRef(null);
    49→  const isStreaming = status === 'streaming' || status === 'submitted';
    50→  const volumeRef = useRef(0);
    51→
    52→  const { voiceAvailable, isConnecting, isRecording, startRecording, stopRecording } = useVoiceInput({
    53→    getToken: getVoiceToken,
    54→    onVolumeChange: (rms) => { volumeRef.current = rms; },
    55→    onTranscript: (text) => {
    56→      setInput((prev) => {
    57→        const needsSpace = prev && !prev.endsWith(' ');
    58→        return prev + (needsSpace ? ' ' : '') + text;
    59→      });
    60→    },
    61→    onError: (err) => console.error('[voice]', err),
    62→  });
    63→
    64→  // Auto-resize textarea
    65→  const adjustHeight = useCallback(() => {
    66→    const textarea = textareaRef.current;
    67→    if (!textarea) return;
    68→    textarea.style.height = 'auto';
    69→    textarea.style.height = `${Math.min(textarea.scrollHeight, 200)}px`;
    70→  }, []);
    71→
    72→  useEffect(() => {
    73→    adjustHeight();
    74→  }, [input, adjustHeight]);
    75→
    76→  // Focus textarea on mount
    77→  useEffect(() => {
    78→    textareaRef.current?.focus();
    79→  }, []);
    80→
    81→  // Close dropdown on outside click
    82→  useEffect(() => {
    83→    if (!modeDropdownOpen) return;
    84→    const handleClickOutside = (e) => {
    85→      if (dropdownRef.current && !dropdownRef.current.contains(e.target)) {
    86→        setModeDropdownOpen(false);
    87→      }
    88→    };
    89→    document.addEventListener('mousedown', handleClickOutside);
    90→    return () => document.removeEventListener('mousedown', handleClickOutside);
    91→  }, [modeDropdownOpen]);
    92→
    93→  const handleFiles = useCallback((fileList) => {
    94→    const newFiles = Array.from(fileList).filter(isAcceptedType);
    95→    if (newFiles.length === 0) return;
    96→
    97→    // Read files outside state updater to avoid React strict mode double-invocation
    98→    newFiles.forEach((file) => {
    99→      const reader = new FileReader();
   100→      reader.onload = () => {
   101→        setFiles((current) => {
   102→          if (current.length >= MAX_FILES) return current;
   103→          return [...current, { file, previewUrl: reader.result }];
   104→        });
   105→      };
   106→      reader.readAsDataURL(file);
   107→    });
   108→  }, [setFiles]);
   109→
   110→  const removeFile = (index) => {
   111→    setFiles((prev) => prev.filter((_, i) => i !== index));
   112→  };
   113→
   114→  const handleSubmit = (e) => {
   115→    if (e) e.preventDefault();
   116→    if (disabled || (!input.trim() && files.length === 0) || isStreaming) return;
   117→    if (canSendOverride !== undefined && !canSendOverride) return;
   118→    onSubmit();
   119→  };
   120→
   121→  const handleKeyDown = (e) => {
   122→    if (e.key === 'Enter' && !e.shiftKey) {
   123→      e.preventDefault();
   124→      handleSubmit();
   125→    }
   126→  };
   127→
   128→  const handleDragOver = (e) => {
   129→    e.preventDefault();
   130→    setIsDragging(true);
   131→  };
   132→
   133→  const handleDragLeave = (e) => {
   134→    e.preventDefault();
   135→    setIsDragging(false);
   136→  };
   137→
   138→  const handleDrop = (e) => {
   139→    e.preventDefault();
   140→    setIsDragging(false);
   141→    if (e.dataTransfer?.files?.length) {
   142→      handleFiles(e.dataTransfer.files);
   143→    }
   144→  };
   145→
   146→  const canSend = canSendOverride !== undefined
   147→    ? canSendOverride && (input.trim() || files.length > 0)
   148→    : (input.trim() || files.length > 0);
   149→
   150→  // Disabled state — show locked message
   151→  if (disabled && !isStreaming) {
   152→    const disabledContent = (
   153→      <div className={cn("flex flex-col rounded-xl border border-border bg-muted p-2", className)}>
   154→        <div className="flex items-center px-2 py-1.5">
   155→          <span className="text-sm text-muted-foreground">{placeholder}</span>
   156→        </div>
   157→      </div>
   158→    );
   159→    if (bare) return disabledContent;
   160→    return (
   161→      <div className="mx-auto w-full max-w-4xl px-1.5 pb-[max(1rem,var(--safe-area-bottom))] md:px-6">
   162→        {disabledContent}
   163→      </div>
   164→    );
   165→  }
   166→
   167→  const formContent = (
   168→    <form onSubmit={handleSubmit} className="relative">
   169→      <div
   170→          className={cn(
   171→            'flex flex-col rounded-xl border bg-muted p-2 transition-colors',
   172→            isDragging ? 'border-primary bg-primary/5' : 'border-border',
   173→            className
   174→          )}
   175→          onDragOver={handleDragOver}
   176→          onDragLeave={handleDragLeave}
   177→          onDrop={handleDrop}
   178→        >
   179→          {/* File preview strip */}
   180→          {files.length > 0 && (
   181→            <div className="mb-2 flex gap-2 overflow-x-auto px-1 py-1">
   182→              {files.map((f, i) => {
   183→                const isImage = f.file.type.startsWith('image/');
   184→                return (
   185→                  <div key={i} className="group relative flex-shrink-0">
   186→                    {isImage ? (
   187→                      <img
   188→                        src={f.previewUrl}
   189→                        alt={f.file.name}
   190→                        className="h-16 w-16 rounded-lg object-cover"
   191→                      />
   192→                    ) : (
   193→                      <div className="flex h-16 items-center gap-1.5 rounded-lg bg-foreground/10 px-3">
   194→                        <FileTextIcon size={14} />
   195→                        <span className="max-w-[100px] truncate text-xs">
   196→                          {f.file.name}
   197→                        </span>
