     1→import { v4 as uuidv4 } from 'uuid';
     2→import { z } from 'zod';
     3→import { githubApi } from './github.js';
     4→import { createModel } from '../ai/model.js';
     5→
     6→/**
     7→ * Generate a short descriptive title for a job using the LLM.
     8→ * Uses structured output to avoid thinking-token leaks with extended-thinking models.
     9→ * @param {string} jobDescription - The full job description
    10→ * @returns {Promise<string>} ~10 word title
    11→ */
    12→async function generateJobTitle(jobDescription) {
    13→  try {
    14→    const model = await createModel({ maxTokens: 100 });
    15→    const response = await model.withStructuredOutput(z.object({ title: z.string() })).invoke([
    16→      ['system', 'Generate a descriptive ~10 word title for this agent job. The title should clearly describe what the job will do.'],
    17→      ['human', jobDescription],
    18→    ]);
    19→    return response.title.trim() || jobDescription.slice(0, 80);
    20→  } catch {
    21→    // Fallback: first line, truncated
    22→    const firstLine = jobDescription.split('\n').find(l => l.trim()) || jobDescription;
    23→    return firstLine.replace(/^#+\s*/, '').trim().split(/\s+/).slice(0, 10).join(' ');
    24→  }
    25→}
    26→
    27→/**
    28→ * Create a new job branch with job.config.json
    29→ * @param {string} jobDescription - The job description
    30→ * @param {Object} [options] - Optional overrides
    31→ * @param {string} [options.llmProvider] - LLM provider override (e.g. 'openai', 'anthropic')
    32→ * @param {string} [options.llmModel] - LLM model override (e.g. 'gpt-4o', 'claude-sonnet-4-5-20250929')
    33→ * @param {string} [options.agentBackend] - Agent backend override ('pi' or 'claude-code')
    34→ * @returns {Promise<{job_id: string, branch: string, title: string}>} - Job ID, branch name, and title
    35→ */
    36→async function createJob(jobDescription, options = {}) {
    37→  const { GH_OWNER, GH_REPO } = process.env;
    38→  const jobId = uuidv4();
    39→  const branch = `job/${jobId}`;
    40→  const repo = `/repos/${GH_OWNER}/${GH_REPO}`;
    41→
    42→  // Generate a short descriptive title
    43→  const title = await generateJobTitle(jobDescription);
    44→
    45→  // 1. Get main branch SHA and its tree SHA
    46→  const mainRef = await githubApi(`${repo}/git/ref/heads/main`);
    47→  const mainSha = mainRef.object.sha;
    48→  const mainCommit = await githubApi(`${repo}/git/commits/${mainSha}`);
    49→  const baseTreeSha = mainCommit.tree.sha;
    50→
    51→  // 2. Build job.config.json — single source of truth for job metadata
    52→  const config = { title, job: jobDescription };
    53→  if (options.llmProvider) config.llm_provider = options.llmProvider;
    54→  if (options.llmModel) config.llm_model = options.llmModel;
    55→  if (options.agentBackend) config.agent_backend = options.agentBackend;
    56→
    57→  const treeEntries = [
    58→    {
    59→      path: `logs/${jobId}/job.config.json`,
    60→      mode: '100644',
    61→      type: 'blob',
    62→      content: JSON.stringify(config, null, 2),
    63→    },
    64→  ];
    65→
    66→  // 3. Create tree (base_tree preserves all existing files)
    67→  const tree = await githubApi(`${repo}/git/trees`, {
    68→    method: 'POST',
    69→    body: JSON.stringify({
    70→      base_tree: baseTreeSha,
    71→      tree: treeEntries,
    72→    }),
    73→  });
    74→
    75→  // 4. Create a single commit with job config
    76→  const commit = await githubApi(`${repo}/git/commits`, {
    77→    method: 'POST',
    78→    body: JSON.stringify({
    79→      message: `🤖 Agent Job: ${title}`,
    80→      tree: tree.sha,
    81→      parents: [mainSha],
    82→    }),
    83→  });
    84→
    85→  // 5. Create branch pointing to the commit (triggers run-job.yml)
    86→  await githubApi(`${repo}/git/refs`, {
    87→    method: 'POST',
    88→    body: JSON.stringify({
    89→      ref: `refs/heads/${branch}`,
    90→      sha: commit.sha,
    91→    }),
    92→  });
    93→
    94→  return { job_id: jobId, branch, title };
    95→}
    96→
    97→export { createJob };
    98→

