   226→  }
   227→
   228→  const { GH_OWNER, GH_REPO } = process.env;
   229→  const OBSIDIAN_HOST = getConfig('OBSIDIAN_HOST');
   230→  const OBSIDIAN_API_KEY = getConfig('OBSIDIAN_API_KEY');
   231→
   232→  if (!OBSIDIAN_HOST || !OBSIDIAN_API_KEY) {
   233→    return Response.json({ error: 'Obsidian not configured' }, { status: 500 });
   234→  }
   235→
   236→  try {
   237→    const files = await githubApi(
   238→      `/repos/${GH_OWNER}/${GH_REPO}/contents/logs/${job_id}?ref=${encodeURIComponent(commit_sha)}`
   239→    );
   240→
   241→    if (!Array.isArray(files)) {
   242→      return Response.json({ ok: true, synced: 0, reason: 'no log directory' });
   243→    }
   244→
   245→    const outputFiles = files.filter(f => f.name.endsWith('.md') && !VAULT_SKIP_FILES.has(f.name));
   246→    if (outputFiles.length === 0) {
   247→      return Response.json({ ok: true, synced: 0, reason: 'no output files' });
   248→    }
