   252→      const fileData = await githubApi(
   253→        `/repos/${GH_OWNER}/${GH_REPO}/contents/logs/${job_id}/${file.name}?ref=${encodeURIComponent(commit_sha)}`
   254→      );
   255→      const content = Buffer.from(fileData.content, 'base64').toString('utf-8');
   256→
   257→      // Check frontmatter for explicit vault path
   258→      let vaultPath = `05-Agent-Outputs/${file.name}`;
   259→      const match = content.match(/^---\n[\s\S]*?vault-path:\s*(.+)\n[\s\S]*?---/);
   260→      if (match) vaultPath = match[1].trim();
