   268→      if (res.ok || res.status === 204) {
   269→        synced.push({ file: file.name, vault_path: vaultPath });
   270→        console.log(`[vault-sync] ${file.name} → ${vaultPath}`);
   271→      } else {
   272→        console.error(`[vault-sync] Failed: ${vaultPath} HTTP ${res.status}`);
   273→      }
   274→    }
   275→
   276→    console.log(`[vault-sync] Job ${job_id.slice(0, 8)}: ${synced.length}/${outputFiles.length} files`);
   277→    return Response.json({ ok: true, synced: synced.length, files: synced });
   278→  } catch (err) {
   279→    console.error('[vault-sync] Error:', err.message);
   280→    return Response.json({ error: 'Vault sync failed' }, { status: 500 });
   281→  }
   282→}
