     9→/**
    10→ * Ensure a chat exists in the DB and save a message.
    11→ * Centralized so every channel gets persistence automatically.
    12→ *
    13→ * @param {string} threadId - Chat/thread ID
    14→ * @param {string} role - 'user' or 'assistant'
    15→ * @param {string} text - Message text
    16→ * @param {object} [options] - { userId, chatTitle }
    17→ */
    18→function persistMessage(threadId, role, text, options = {}) {
    19→  try {
    20→    if (!getChatById(threadId)) {
    21→      createChat(options.userId || 'unknown', options.chatTitle || 'New Chat', threadId);
    22→    }
