    24→  } catch (err) {
    25→    console.error(`[persistMessage] Failed to save ${role} message to chat ${threadId} (${text?.length ?? 0} chars):`, err);
    26→  }
    27→}
    28→
    29→/**
    30→ * Process a chat message through the LangGraph agent.
    31→ * Saves user and assistant messages to the DB automatically.
    32→ *
    33→ * @param {string} threadId - Conversation thread ID (from channel adapter)
    34→ * @param {string} message - User's message text
    35→ * @param {Array} [attachments=[]] - Normalized attachments from adapter
    36→ * @param {object} [options] - { userId, chatTitle } for DB persistence
    37→ * @returns {Promise<string>} AI response text
    38→ */
    39→async function chat(threadId, message, attachments = [], options = {}) {
    40→  const agent = await getChatAgent();
    41→
    42→  // Save user message to DB
    43→  persistMessage(threadId, 'user', message || '[attachment]', options);
    44→
    45→  // Build content blocks: text + any image attachments as base64 vision
    46→  const content = [];
    47→
    48→  if (message) {
    49→    content.push({ type: 'text', text: message });
    50→  }
    51→
    52→  for (const att of attachments) {
    53→    if (att.category === 'image') {
    54→      content.push({
    55→        type: 'image_url',
    56→        image_url: {
    57→          url: `data:${att.mimeType};base64,${att.data.toString('base64')}`,
    58→        },
    59→      });
    60→    }
    61→    // Documents: future handling
    62→  }
    63→
    64→  // If only text and no attachments, simplify to a string
    65→  const messageContent = content.length === 1 && content[0].type === 'text'
    66→    ? content[0].text
    67→    : content;
    68→
    69→  const result = await agent.invoke(
    70→    { messages: [new HumanMessage({ content: messageContent })] },
    71→    { configurable: { thread_id: threadId } }
    72→  );
    73→
    74→  const lastMessage = result.messages[result.messages.length - 1];
    75→
    76→  // LangChain message content can be a string or an array of content blocks
    77→  let response;
    78→  if (typeof lastMessage.content === 'string') {
    79→    response = lastMessage.content;
    80→  } else {
    81→    response = lastMessage.content
    82→      .filter((block) => block.type === 'text')
    83→      .map((block) => block.text)
    84→      .join('\n');
    85→  }
    86→
    87→  // Save assistant response to DB
    88→  persistMessage(threadId, 'assistant', response, options);
    89→
    90→  // Auto-generate title for new chats
    91→  if (options.userId && message) {
    92→    autoTitle(threadId, message).catch(() => {});
    93→  }
    94→
    95→  return response;
    96→}
    97→
    98→/**
    99→ * Process a chat message with streaming (for channels that support it).
   100→ * Saves user and assistant messages to the DB automatically.
   101→ *
   102→ * @param {string} threadId - Conversation thread ID
   103→ * @param {string} message - User's message text
   104→ * @param {Array} [attachments=[]] - Image/PDF attachments: { category, mimeType, dataUrl }
   105→ * @param {object} [options] - { userId, chatTitle, skipUserPersist } for DB persistence
   106→ * @returns {AsyncIterableIterator<string>} Stream of text chunks
   107→ */
   108→async function* chatStream(threadId, message, attachments = [], options = {}) {
   109→  let agent;
   110→
   111→  // Code mode: set up workspace + code agent
   112→  if (options.repo && options.branch) {
   113→    const existingChat = getChatById(threadId);
   114→    let workspaceId;
   115→
   116→    if (!existingChat) {
   117→      // Workspace already created client-side — just create the chat and link
   118→      workspaceId = options.workspaceId;
   119→      if (!workspaceId) {
   120→        // Fallback: create workspace server-side (e.g. non-browser callers)
   121→        const { createCodeWorkspace, updateFeatureBranch } = await import('../db/code-workspaces.js');
   122→        const workspace = createCodeWorkspace(options.userId || 'unknown', {
   123→          repo: options.repo,
   124→          branch: options.branch,
   125→        });
   126→        workspaceId = workspace.id;
   127→        const shortId = workspaceId.replace(/-/g, '').slice(0, 8);
   128→        const featureBranch = `thepopebot/new-chat-${shortId}`;
   129→        updateFeatureBranch(workspaceId, featureBranch);
   130→      }
   131→      createChat(options.userId || 'unknown', 'New Chat', threadId);
   132→      linkChatToWorkspace(threadId, workspaceId);
   133→    } else {
   134→      workspaceId = existingChat.codeWorkspaceId;
   135→    }
   136→
   137→    setCurrentCodeModeType(options.codeModeType || 'plan');
   138→    agent = await getCodeAgent({
   139→      repo: options.repo,
   140→      branch: options.branch,
   141→      workspaceId,
   142→      chatId: threadId,
   143→    });
   144→  } else {
   145→    agent = await getChatAgent();
   146→  }
   147→
   148→  // Save user message to DB (skip on regeneration — message already exists)
   149→  if (!options.skipUserPersist) {
   150→    persistMessage(threadId, 'user', message || '[attachment]', options);
   151→  }
   152→
   153→  // Build content blocks: text + any image/PDF attachments as vision
   154→  const content = [];
   155→
   156→  if (message) {
   157→    content.push({ type: 'text', text: message });
   158→  }
   159→
   160→  for (const att of attachments) {
   161→    if (att.category === 'image') {
   162→      // Support both dataUrl (web) and Buffer (Telegram) formats
