   165→        : `data:${att.mimeType};base64,${att.data.toString('base64')}`;
   166→      content.push({
   167→        type: 'image_url',
   168→        image_url: { url },
   169→      });
   170→    }
   171→  }
   172→
   173→  // If only text and no attachments, simplify to a string
   174→  const messageContent = content.length === 1 && content[0].type === 'text'
   175→    ? content[0].text
   176→    : content;
   177→
   178→  try {
   179→    const stream = await agent.stream(
   180→      { messages: [new HumanMessage({ content: messageContent })] },
   181→      { configurable: { thread_id: threadId }, streamMode: 'messages' }
   182→    );
   183→
   184→    let fullText = '';
   185→    let webSearchInput = '';
   186→    const toolCallNames = {};
   187→    const pendingToolCalls = new Map();
   188→    let headlessContainer = null;
