   193→      const msgType = msg._getType?.();
   194→
   195→      if (msgType === 'ai') {
   196→        // Debug: log web search content blocks to see actual shape
   197→        // Tool calls — AIMessage.tool_calls is an array of { id, name, args }
   198→        if (msg.tool_calls?.length > 0) {
   199→          for (const tc of msg.tool_calls) {
   200→            toolCallNames[tc.id] = tc.name;
   201→            pendingToolCalls.set(tc.id, { toolName: tc.name, args: tc.args });
   202→            yield {
   203→              type: 'tool-call',
   204→              toolCallId: tc.id,
   205→              toolName: tc.name,
   206→              args: tc.args,
   207→            };
   208→          }
   209→        }
   210→
   211→        // Text content (wrapped in structured object)
