     1→import { ChatAnthropic } from '@langchain/anthropic';
     2→import { getConfig } from '../config.js';
     3→import { BUILTIN_PROVIDERS } from '../llm-providers.js';
     4→
     5→// These models require thought_signature round-tripping which @langchain/google-genai doesn't support.
     6→// Auto-replace with gemini-2.5-flash until we migrate to @langchain/google (see issue #201).
     7→const GEMINI_UNSUPPORTED_MODELS = ['gemini-2.5-pro', 'gemini-3'];
     8→const GEMINI_FALLBACK = 'gemini-2.5-flash';
     9→
    10→/**
    11→ * Create a LangChain chat model based on DB/env configuration.
    12→ *
    13→ * @param {object} [options]
    14→ * @param {number} [options.maxTokens] - Max tokens for the response
    15→ * @returns {import('@langchain/core/language_models/chat_models').BaseChatModel}
    16→ */
    17→export async function createModel(options = {}) {
    18→  const provider = getConfig('LLM_PROVIDER');
    19→  const modelName = getConfig('LLM_MODEL');
    20→  const maxTokens = options.maxTokens || Number(getConfig('LLM_MAX_TOKENS')) || 4096;
    21→
    22→  // Custom provider (not in BUILTIN_PROVIDERS) → OpenAI-compatible
    23→  if (!BUILTIN_PROVIDERS[provider]) {
    24→    const { ChatOpenAI } = await import('@langchain/openai');
    25→    const { getCustomProvider } = await import('../db/config.js');
    26→    const custom = getCustomProvider(provider);
    27→    if (!custom) throw new Error(`Unknown LLM provider: ${provider}`);
    28→    const config = { modelName: custom.model || modelName, maxTokens };
    29→    config.apiKey = custom.apiKey || 'not-needed';
    30→    if (custom.baseUrl) {
    31→      config.configuration = { baseURL: custom.baseUrl };
    32→    }
    33→    return new ChatOpenAI(config);
    34→  }
    35→
    36→  switch (provider) {
    37→    case 'anthropic': {
    38→      const apiKey = getConfig('ANTHROPIC_API_KEY');
    39→      if (!apiKey) {
    40→        throw new Error('ANTHROPIC_API_KEY is required — set it on the Settings > Chat page');
    41→      }
    42→      return new ChatAnthropic({
    43→        modelName,
    44→        maxTokens,
    45→        anthropicApiKey: apiKey,
    46→      });
    47→    }
    48→    case 'openai': {
    49→      const { ChatOpenAI } = await import('@langchain/openai');
    50→      const apiKey = getConfig('OPENAI_API_KEY');
    51→      const baseURL = getConfig('OPENAI_BASE_URL');
    52→      if (!apiKey && !baseURL) {
    53→        throw new Error('OPENAI_API_KEY is required — set it on the Settings > Chat page');
