export function saveMessage(chatId, role, content, id = null) {
  const db = getDb();
  const now = Date.now();
  const message = {
    id: id || randomUUID(),
    chatId,
    role,
    content,
    createdAt: now,
  };
  db.insert(messages).values(message).run();
  db.update(chats).set({ updatedAt: now }).where(eq(chats.id, chatId)).run();
  return message;
}

